2. **Create handler function** (before line 1634):
```cpp
static common_chat_params common_chat_params_init_your_model(
    const common_chat_template & tmpl,
    const autoparser::generation_params & inputs) {

    common_chat_params data;

    // Step A: Transform messages if needed
    auto adjusted_messages = json::array();
    for (const auto & msg : inputs.messages) {
        // Custom message transformation logic
    }

    // Step B: Render template with adjusted messages
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs, adjusted_messages);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = true;
    data.thinking_start_tag = "[YOUR_START]";
    data.thinking_end_tag = "[YOUR_END]";

    // Step C: Build PEG parser using DSL
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto generation_prompt = p.prefix(inputs.generation_prompt, "[YOUR_START]");
        auto reasoning = extract_reasoning ? 
            p.optional("[YOUR_START]" + p.reasoning(p.until("[YOUR_END]")) + "[YOUR_END]") : 
            p.eps();

        // Tool calls handling
        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
            auto tool_choice = p.choice();
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                std::string name = function.at("name");
                const auto & schema = function.at("parameters");

                tool_choice |= p.rule("tool-" + name, 
                    p.tool_open(...) + p.tool_args(...));
            });
            return generation_prompt + (reasoning << p.content(...) << p.trigger_rule("tool-call", ...));
        }

        // Content-only fallback
        return generation_prompt + (reasoning << p.content(p.rest()));
    });

    data.parser = parser.save();

    // Step D: Build grammar if needed
    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & schema = tool.at("function").at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "YOUR_TRIGGER" }
        };
    }

    return data;
}
```

