static common_chat_params common_chat_params_init_mistral_instruct_v3(
    const common_chat_template &          tmpl,
    const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Mistral Instruct v0.3 has no dedicated system role token; the system
    // message is prepended to the content of the first user turn instead.
    std::string system_prompt;
    auto        adjusted_messages = json::array();
    bool        system_injected   = false;

    for (const auto & msg : inputs.messages) {
        const auto role = msg.value("role", "");
        if (role == "system") {
            // Accumulate system content to prepend to the first user turn.
            if (!system_prompt.empty()) {
                system_prompt += "\n\n";
            }
            system_prompt += msg.value("content", "");
            continue;
        }
        if (!system_injected && !system_prompt.empty() && role == "user") {
            auto adjusted       = msg;
            adjusted["content"] = system_prompt + "\n\n" + msg.value("content", "");
            system_injected     = true;
            adjusted_messages.push_back(adjusted);
            continue;
        }
        adjusted_messages.push_back(msg);
    }

    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Mistral Instruct v0.3 is a plain conversation format:
        // [INST] user [/INST] assistant </s>
        // No tool calls or reasoning tokens; capture all output as content.
        return p.prefix(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    return data;
}

